function uid() { return Math.random().toString(36).slice(2, 10); }
function today() { return new Date().toISOString().slice(0, 10); }
function formatDate(iso) {
  if (!iso) return "";
  return new Date(iso).toLocaleDateString("en-US", { month:"short", day:"numeric", year:"numeric" });
}
function formatDateTime(iso) {
  if (!iso) return "";
  return new Date(iso).toLocaleString("en-US", { month:"short", day:"numeric", year:"numeric", hour:"numeric", minute:"2-digit", hour12:true });
}
function getInitials(name) { return name ? name.slice(0,2).toUpperCase() : "??"; }

async function downloadFile(f) {
  if (!Capacitor.isNativePlatform()) {
    const a = document.createElement("a");
    a.href = f.dataUrl;
    a.download = f.name || "file";
    document.body.appendChild(a);
    a.click();
    a.remove();
    return;
  }
  try {
    const base64 = f.dataUrl.slice(f.dataUrl.indexOf(",") + 1);
    const written = await Filesystem.writeFile({
      path: f.name || `file-${uid()}`,
      data: base64,
      directory: Directory.Cache,
    });
    await Share.share({ url: written.uri, dialogTitle: `Save ${f.name || "file"}` });
  } catch (e) {
    if (e?.message !== "Share canceled") alert("Couldn't save this file. Please try again.");
  }
}

const DOG_COLORS = ["#D97706","#7C3AED","#0891B2","#16A34A","#C0392B","#EA580C","#9333EA","#0284C7"];

const BEHAVIOR_FLAG_PHRASES = ["guarding","reactivity","reaction","aggression","separation anxiety","kennel aggression","lunging","possession","not responding","mouthing","growling","unresponsive"];
function detectFlaggedBehaviors(noteText, existingBehaviors) {
  const lower = noteText.toLowerCase();
  const existingLabels = new Set((existingBehaviors||[]).filter(b=>!b.resolved).map(b=>b.label.toLowerCase()));
  return BEHAVIOR_FLAG_PHRASES
    .filter(phrase => lower.includes(phrase) && !existingLabels.has(phrase))
    .map(phrase => ({ id:uid(), label: phrase.charAt(0).toUpperCase()+phrase.slice(1), severity:"high", resolved:false }));
}

const MOTIVATION_EMOJI = { "Very low":"😥", "Low":"🙁", "Moderate":"😐", "High":"😃", "Very high":"🔥" };

const CTO_LOGO = "data:image/png;base64,";

// ── Phase definitions ─────────────────────────────────────────────────────────
const PHASES = [
  { key:"p1", label:"Day 1–5",   prefix:["Day 1-3","Day 1-5","Day 3-5"] },
  { key:"p2", label:"Day 6–10",  prefix:["Day 6-10"] },
  { key:"p3", label:"Day 11–14", prefix:["Day 11-14"] },
  { key:"p4", label:"Day 14–21", prefix:["Day 14-21"] },
];

function getPhaseForGoal(label) {
  for (const p of PHASES) {
    if (p.prefix.some(pfx => label.startsWith(pfx))) return p.key;
  }
  return "custom";
}

const CTO_CHECKLIST = [
  "Day 1-3: Engagement Exercises","Day 1-3: Introduction to the Remote Training Collar",
  "Day 3-5: Prong Collar Introduction","Day 1-5: Introduction to the Boards",
  "Day 1-5: Leash Pressure","Day 1-5: Recall Protocols","Day 1-5: Two Foot Off The Board Drill",
  "Day 1-5: Settling in Crate Drills","Day 1-5: Crate Exercise - Teaching to Go Inside the Kennel",
  "Day 1-5: Crate Exercise - Lay Down","Day 6-10: Public Access Trip",
  "Day 6-10: Exposure to New Environments","Day 6-10: Two Person Recall Exercises",
  "Day 6-10: Start Incorporating Distractions Into Training",
  "Day 6-10: Dog Tethered in Place for Duration Exercises",
  "Day 11-14: Heavy Public Access Trips","Day 11-14: Heavy Distractions",
  "Day 11-14: Pack Walks","Day 11-14: Training Off Location",
  "Day 14-21: Proofing and Testing","Day 14-21: Exposing to New Environments",
  "Day 14-21: Fine Tune Training","Day 14-21: Finishing Dog",
];
function makeDefaultChecklist() { return CTO_CHECKLIST.map(label=>({id:uid(),label,done:false})); }

// ── Phase progress helpers ────────────────────────────────────────────────────
function getPhaseProgress(checklist) {
  const result = {};
  for (const p of PHASES) {
    const items = checklist.filter(g => getPhaseForGoal(g.label) === p.key);
    const done  = items.filter(g => g.done).length;
    result[p.key] = { total: items.length, done };
  }
  return result;
}

function currentPhaseKey(checklist) {
  const progress = getPhaseProgress(checklist);
  for (const p of PHASES) {
    if (progress[p.key].total > 0 && progress[p.key].done < progress[p.key].total) return p.key;
  }
  return PHASES[PHASES.length-1].key;
}

