// ── Admin config ──────────────────────────────────────────────────────────────
const ADMIN_USERNAMES = ["brookeoprandy"];
function isAdmin(username) {
  const key = (username||"").toLowerCase();
  if (ADMIN_USERNAMES.includes(key)) return true;
  return !!loadUsers()[key]?.admin;
}


