// ── Phase ring (goals tab) ────────────────────────────────────────────────────
function PhaseRing({ done, total, color, label }) {
  const r = 18; const circ = 2 * Math.PI * r;
  const pct = total ? done/total : 0;
  return (
    <div style={{display:"flex",alignItems:"center",gap:8}}>
      <svg width={44} height={44} viewBox="0 0 44 44">
        <circle cx={22} cy={22} r={r} fill="none" stroke="#e5e5e5" strokeWidth={4}/>
        <circle cx={22} cy={22} r={r} fill="none" stroke={pct===1?"#16A34A":color} strokeWidth={4}
          strokeDasharray={circ} strokeDashoffset={circ*(1-pct)}
          strokeLinecap="round" transform="rotate(-90 22 22)" style={{transition:"stroke-dashoffset 0.4s"}}/>
        <text x={22} y={26} textAnchor="middle" fontSize={10} fontWeight={700} fill={pct===1?"#16A34A":color}>{Math.round(pct*100)}%</text>
      </svg>
      <div>
        <div style={{fontSize:13,fontWeight:600,color:"#1a1a1a"}}>{label}</div>
        <div style={{fontSize:11,color:"#888"}}>{done}/{total} complete</div>
      </div>
    </div>
  );
}

