// ── Confetti ──────────────────────────────────────────────────────────────────
function Confetti({ visible }) {
  const canvasRef = useRef(null);
  const rafRef    = useRef(null);
  const startRef  = useRef(null);
  useEffect(() => {
    if (!visible) return;
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth; canvas.height = window.innerHeight;
    const COLORS = ["#8B0000","#ffffff","#D97706","#7C3AED","#16A34A","#EA580C","#0891B2"];
    const pieces = Array.from({length:140},()=>({
      x:Math.random()*canvas.width, y:-Math.random()*canvas.height*0.5,
      w:6+Math.random()*8, h:10+Math.random()*8,
      color:COLORS[Math.floor(Math.random()*COLORS.length)],
      rot:Math.random()*Math.PI*2, rotV:(Math.random()-0.5)*0.15,
      vx:(Math.random()-0.5)*2.5, vy:2.5+Math.random()*3.5,
      shape:Math.random()>0.5?"rect":"circle",
    }));
    function draw(ts) {
      if(!startRef.current) startRef.current=ts;
      if(ts-startRef.current>2600){ctx.clearRect(0,0,canvas.width,canvas.height);return;}
      ctx.clearRect(0,0,canvas.width,canvas.height);
      pieces.forEach(p=>{
        p.x+=p.vx; p.y+=p.vy; p.rot+=p.rotV;
        if(p.y>canvas.height+20){p.y=-20;p.x=Math.random()*canvas.width;}
        ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.rot); ctx.fillStyle=p.color;
        if(p.shape==="circle"){ctx.beginPath();ctx.arc(0,0,p.w/2,0,Math.PI*2);ctx.fill();}
        else ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);
        ctx.restore();
      });
      rafRef.current=requestAnimationFrame(draw);
    }
    startRef.current=null; rafRef.current=requestAnimationFrame(draw);
    return()=>{if(rafRef.current)cancelAnimationFrame(rafRef.current);};
  },[visible]);
  if(!visible) return null;
  return (
    <div style={{position:"fixed",inset:0,zIndex:500,pointerEvents:"none",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <canvas ref={canvasRef} style={{position:"absolute",inset:0,width:"100%",height:"100%"}}/>
      <div style={{position:"relative",background:"#fff",borderRadius:16,padding:"1.75rem 2.5rem",boxShadow:"0 8px 40px rgba(0,0,0,0.18)",textAlign:"center",animation:"popIn 0.3s ease"}}>
        <div style={{fontSize:42,marginBottom:8}}>🎉</div>
        <div style={{fontSize:18,fontWeight:700,color:"#1a1a1a",marginBottom:4}}>Session logged!</div>
        <div style={{fontSize:13,color:"#888"}}>Great work — keep it up!</div>
      </div>
      <style>{`@keyframes popIn{from{transform:scale(0.7);opacity:0}to{transform:scale(1);opacity:1}}`}</style>
    </div>
  );
}

// ── Summary Tab ───────────────────────────────────────────────────────────────
function SummaryTab({ dog, updateDog }) {
  const [summary, setSummary]   = useState(dog.aiSummary || "");
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState("");
  const [generated, setGenerated] = useState(!!dog.aiSummary);
  const [generatedAt, setGeneratedAt] = useState(dog.aiSummaryGeneratedAt || null);

  async function generateSummary() {
    if (!dog.sessions.length) return;
    setLoading(true); setError(""); setSummary(""); setGenerated(false);

    const sessionText = [...dog.sessions]
      .sort((a,b) => a.date > b.date ? 1 : -1)
      .map((s,i) => `Session ${i+1} (${s.date}${s.trainer ? `, logged by ${s.trainer}` : ""}${s.motivation ? `, motivation: ${s.motivation}` : ""}):\n${s.note}`)
      .join("\n\n");

    const prompt = `You are a professional dog training assistant. Below are all the session logs for a dog named ${dog.name} (${dog.breed}${dog.age ? `, ${dog.age}` : ""}) whose training goal is: "${dog.goal}".

Session logs (oldest to newest):
${sessionText}

Please write a clear, professional training progress summary for this dog. Include:
1. Overall progress and highlights
2. Key behaviors or skills improved
3. Any patterns or concerns noticed across sessions
4. Recommended next steps for the trainer

Keep it concise, practical, and trainer-focused. Do not use markdown headers — write in clean paragraphs.`;

    try {
      const res = await fetch(`${API_BASE_URL}/api/generate-summary`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt, max_tokens: 1000 }),
      });
      const data = await res.json();
      const text = data.content?.map(c => c.text || "").join("") || "";
      if (!text) throw new Error("Empty response");
      const now = new Date().toISOString();
      setSummary(text);
      setGenerated(true);
      setGeneratedAt(now);
      updateDog(dog.id, d => ({...d, aiSummary: text, aiSummaryGeneratedAt: now}));
    } catch(e) {
      setError("Failed to generate summary. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div>
      <div style={{background:"#fff",border:"1px solid #e8e0d8",borderRadius:10,padding:"14px 16px",marginBottom:16}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10}}>
          <div>
            <div style={{fontSize:13,fontWeight:600,color:"#1a1a1a",marginBottom:3}}>AI Training Summary</div>
            <div style={{fontSize:12,color:"#aaa"}}>Generates a progress summary based on all {dog.sessions.length} session{dog.sessions.length!==1?"s":""} logged for {dog.name}.</div>
          </div>
          <button
            onClick={generateSummary}
            disabled={loading || dog.sessions.length===0}
            style={{...btnPrim, opacity: dog.sessions.length===0 ? 0.5 : 1, cursor: dog.sessions.length===0 ? "not-allowed" : "pointer", display:"flex", alignItems:"center", gap:6, whiteSpace:"nowrap"}}
          >
            {loading ? "Generating…" : generated ? "Regenerate" : "Generate Summary"}
          </button>
        </div>
      </div>

      {dog.sessions.length===0&&(
        <div style={{textAlign:"center",color:"#ccc",padding:"2.5rem",fontSize:13,borderRadius:10,border:"1.5px dashed #e8e0d8"}}>
          No sessions logged yet. Add sessions first to generate a summary.
        </div>
      )}

      {loading&&(
        <div style={{background:"#fff",border:"1px solid #e8e0d8",borderRadius:10,padding:"2rem",textAlign:"center"}}>
          <div style={{fontSize:13,color:"#aaa",marginBottom:12}}>Analyzing {dog.sessions.length} session{dog.sessions.length!==1?"s":""} for {dog.name}…</div>
          <div style={{display:"flex",justifyContent:"center",gap:6}}>
            {[0,1,2].map(i=>(
              <div key={i} style={{width:8,height:8,borderRadius:"50%",background:RED,animation:`pulse 1.2s ease-in-out ${i*0.2}s infinite`}}/>
            ))}
          </div>
          <style>{`@keyframes pulse{0%,100%{opacity:0.3;transform:scale(0.8)}50%{opacity:1;transform:scale(1)}}`}</style>
        </div>
      )}

      {error&&!loading&&(
        <div style={{background:"#FEF2F2",border:"1px solid #FECACA",borderRadius:10,padding:"12px 16px",fontSize:13,color:"#991B1B"}}>{error}</div>
      )}

      {summary&&!loading&&(
        <div style={{background:"#fff",border:"1px solid #e8e0d8",borderRadius:10,padding:"20px 22px"}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14,paddingBottom:12,borderBottom:"1px solid #f0ebe4"}}>
            <div>
              <div style={{fontSize:14,fontWeight:700,color:"#1a1a1a"}}>{dog.name} — Progress Summary</div>
              <div style={{fontSize:11,color:"#bbb",marginTop:2}}>Generated {new Date(generatedAt||Date.now()).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric",hour:"numeric",minute:"2-digit",hour12:true})}</div>
            </div>
            <span style={{fontSize:11,fontWeight:500,padding:"3px 10px",borderRadius:99,background:"#F0FDF4",color:"#16A34A",border:"1px solid #BBF7D0"}}>AI Generated</span>
          </div>
          <div style={{fontSize:13,color:"#333",lineHeight:1.8,whiteSpace:"pre-wrap"}}>{summary}</div>
        </div>
      )}
    </div>
  );
}

